import React, { useEffect, useState } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";

export default function Ventas() {
  const [productos, setProductos] = useState([]);
  const [clientes, setClientes] = useState([]);

  const [productoID, setProductoID] = useState("");
  const [cantidad, setCantidad] = useState(1);
  const [carrito, setCarrito] = useState([]);

  const [clienteID, setClienteID] = useState("");
  const [mensaje, setMensaje] = useState("");
  const [ticket, setTicket] = useState(null);
  const [stockActual, setStockActual] = useState(null);

  useEffect(() => {
    cargarProductos();
    cargarClientes();
  }, []);

  const cargarProductos = async () => {
    const res = await axios.get("http://localhost:5000/api/productos");
    setProductos(res.data);
  };

  const cargarClientes = async () => {
    const res = await axios.get("http://localhost:5000/api/clientes");
    setClientes(res.data);
  };

  // ➕ Agregar producto al carrito
  const agregarProducto = () => {
    const prod = productos.find(p => p.ProductoID === Number(productoID));
    if (!prod) return;

    if (prod.Stock < cantidad) {
      setMensaje("❌ Stock insuficiente");
      return;
    }

    setCarrito([...carrito, {
      ProductID: prod.ProductoID,
      Nombre: prod.Nombre,
      Cantidad: cantidad
    }]);

    setCantidad(1);
    setProductoID("");
    setMensaje("");
  };

  // ❌ Eliminar del carrito
  const eliminarProducto = (index) => {
    setCarrito(carrito.filter((_, i) => i !== index));
  };

  // 💰 Realizar venta
  const realizarVenta = async () => {
    if (!clienteID || carrito.length === 0) {
      setMensaje("⚠️ Cliente y productos requeridos");
      return;
    }

    try {
      const res = await axios.post("http://localhost:5000/api/ventas", {
        ClienteID: clienteID,
        productos: carrito.map(p => ({
          ProductID: p.ProductID,
          Cantidad: p.Cantidad
        })),
        EmisorNombre: "Mi Negocio"
      });

      setTicket(res.data);
      setCarrito([]);
      setMensaje("✅ Venta realizada");
      cargarProductos();
    } catch (err) {
      setMensaje(err.response?.data?.error || "Error en la venta");
    }
  };

  // 🖨 Imprimir ticket
  const imprimir = () => {
    const contenido = document.getElementById("ticket").innerHTML;
    const w = window.open("", "", "width=400,height=600");
    w.document.write(`<html><body>${contenido}</body></html>`);
    w.document.close();
    w.print();
  };

  return (
    <div className="container mt-4">

      <h3 className="mb-3">🧾 Ventas</h3>

      {/* Cliente */}
      <select
        className="form-select mb-3"
        value={clienteID}
        onChange={e => setClienteID(e.target.value)}
      >
        <option value="">Seleccione cliente</option>
        {clientes.map(c => (
          <option key={c.ClienteID} value={c.ClienteID}>
            {c.Nombre}
          </option>
        ))}
      </select>

      {/* Producto */}
      <div className="row mb-3">
        <div className="col-md-6">
          <select
            className="form-select"
            value={productoID}
            onChange={e => setProductoID(e.target.value)}
          >
            <option value="">Seleccione producto</option>
            {productos.map(p => (
              <option key={p.ProductoID} value={p.ProductoID}>
                {p.Nombre} (Stock: {p.Stock})
              </option>
            ))}
          </select>
        </div>

        <div className="col-md-3">
          <input
            type="number"
            className="form-control"
            min="1"
            value={cantidad}
            onChange={e => setCantidad(Number(e.target.value))}
          />
        </div>

        <div className="col-md-3">
          <button className="btn btn-primary w-100" onClick={agregarProducto}>
            ➕ Agregar
          </button>
        </div>
      </div>

      {/* Carrito */}
      <table className="table table-bordered">
        <thead>
          <tr>
            <th>Producto</th>
            <th>Cantidad</th>
            <th></th>
          </tr>
        </thead>
        <tbody>
          {carrito.map((p, i) => (
            <tr key={i}>
              <td>{p.Nombre}</td>
              <td>{p.Cantidad}</td>
              <td>
                <button
                  className="btn btn-danger btn-sm"
                  onClick={() => eliminarProducto(i)}
                >
                  ❌
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      <button className="btn btn-success w-100" onClick={realizarVenta}>
        💰 Confirmar Venta
      </button>

      {mensaje && <div className="alert alert-info mt-3">{mensaje}</div>}

      {/* Ticket */}
      {ticket && (
        <div className="card mt-4 p-3" id="ticket">
          <h5 className="text-center">MI NEGOCIO</h5>
          <p>Factura Nº: {ticket.NumeroSecuencia}</p>
          <p>Fecha: {new Date(ticket.Fecha).toLocaleString()}</p>

          <hr />

          {ticket.productos.map((p, i) => (
            <p key={i}>
              {p.Cantidad} x {p.Nombre} - $
              {(p.Subtotal).toFixed(2)}
            </p>
          ))}

          <hr />
          <p>Subtotal: ${ticket.Subtotal.toFixed(2)}</p>
          <p>IVA: ${ticket.IVA.toFixed(2)}</p>
          <h6>Total: ${ticket.Total.toFixed(2)}</h6>

          <button className="btn btn-secondary w-100" onClick={imprimir}>
            🖨 Imprimir Ticket
          </button>
        </div>
      )}
    </div>
  );
}
